## Algorithm: Kahn's Topological Sort

```go
func Analyze(db *sql.DB, specID int64, opts Options) (*ImplOrderResult, error) {
    // 1. Build adjacency + in-degree from cross_references
    registry, _ := storage.GetInvariantRegistryEntries(db, specID)
    authority, _ := storage.GetAuthorityScores(db, specID)

    // Build graph: for each invariant, find what it references
    graph := map[string][]string{}   // node → dependencies
    inDegree := map[string]int{}
    for _, r := range registry {
        inDegree[r.InvariantID] = 0  // initialize
    }
    // Use cross_references to build edges...

    // 2. Kahn's algorithm
    var phases []Phase
    queue := []string{}  // in-degree 0
    for id, deg := range inDegree {
        if deg == 0 { queue = append(queue, id) }
    }

    for phaseNum := 0; len(queue) > 0; phaseNum++ {
        // Sort within-phase by authority descending
        sort.Slice(queue, func(i, j int) bool {
            return authority[queue[i]] > authority[queue[j]]
        })

        phase := Phase{Phase: phaseNum, Elements: /* ... */}
        var nextQueue []string
        for _, id := range queue {
            // Decrement in-degree of dependents
            for _, dep := range reverseDeps[id] {
                inDegree[dep]--
                if inDegree[dep] == 0 { nextQueue = append(nextQueue, dep) }
            }
        }
        phases = append(phases, phase)
        queue = nextQueue
    }

    // 3. Cycle detection: any remaining in-degree > 0
    var cycles [][]string
    for id, deg := range inDegree {
        if deg > 0 { /* trace cycle path */ }
    }
}
