## Pattern A: CLI Command (copy from exemplar.go:52-114)

```go
var myCmd = &cobra.Command{
    Use:   "mycommand [target] [db-path]",
    Short: "One-line description",
    Args:  cobra.RangeArgs(1, 2),  // or cobra.MaximumNArgs(1) for db-only
    RunE:  runMyCommand,
}

func init() {
    myCmd.Flags().BoolVar(&myJSON, "json", false, "Output as JSON")
}

func runMyCommand(cmd *cobra.Command, args []string) error {
    // 1. Parse args
    target := args[0]
    var dbPath string
    if len(args) >= 2 { dbPath = args[1] }
    if dbPath == "" {
        var err error
        dbPath, err = findDB()
        if err != nil { return err }
    }

    // 2. Open DB + get specID
    db, err := storage.Open(dbPath)
    if err != nil { return fmt.Errorf("open database: %w", err) }
    defer db.Close()
    specID, err := storage.GetFirstSpecID(db)
    if err != nil { return fmt.Errorf("no spec found: %w", err) }

    // 3. Call analysis
    result, err := mypackage.Analyze(db, specID, opts)
    if err != nil { return err }

    // 4. Render + print
    out, err := mypackage.Render(result, myJSON)
    if err != nil { return err }
    fmt.Print(out)
    return nil
}
```

