## Pattern D: Query Function (copy from storage/queries.go)

```go
func ListThingsByFilter(db *sql.DB, specID int64, filter string) ([]Thing, error) {
    rows, err := db.Query(
        "SELECT col1, col2 FROM table WHERE spec_id = ? AND filter_col = ? ORDER BY col1",
        specID, filter)
    if err != nil { return nil, err }
    defer rows.Close()
    var results []Thing
    for rows.Next() {
        var t Thing
        if err := rows.Scan(&t.Col1, &t.Col2); err != nil { return nil, err }
        results = append(results, t)
    }
    return results, rows.Err()
}
```

