func Assemble(db *sql.DB, specID int64, domain string, opts Options) (*BundleResult, error) {
    // 1. Load constitution text
    //    Strategy: Find source_files where filepath contains "constitution" or "system"
    //    OR: Find modules with no domain assignment (constitution files)
    //    OR: Get all source_files, subtract module source_files
    //    INVESTIGATE during implementation — check what parser stores
    constitutionText := loadConstitution(db, specID)

    // 2. Load domain modules
    modules, _ := storage.ListModulesByDomain(db, specID, domain)
    var moduleTexts []ModuleText
    for _, m := range modules {
        text, _ := storage.GetSourceFileContent(db, m.SourceFileID)
        moduleTexts = append(moduleTexts, ModuleText{Name: m.ModuleName, Content: text})
    }

    // 3. Load interface stubs from adjacent domains
    boundary, _ := storage.GetDomainBoundaryInvariants(db, specID, domain)
    var stubs []InterfaceStub
    for _, entry := range boundary {
        inv, _ := storage.GetInvariant(db, specID, entry.InvariantID)
        if inv != nil {
            stubs = append(stubs, renderStub(*inv, entry))
        }
    }

    // 4. Assemble content: constitution + modules + stubs
    // 5. Compute budget from GetManifest().HardCeilingLines
    manifest, _ := storage.GetManifest(db, specID)
    ceiling := manifest.HardCeilingLines  // from Manifest struct
}
```

