## Algorithm

```go
func Analyze(db *sql.DB, specID int64, elementID string, opts Options) (*CascadeResult, error) {
    // 1. Look up owner from registry
    registry, _ := storage.GetInvariantRegistryEntries(db, specID)
    var owner, domain string
    for _, r := range registry {
        if r.InvariantID == elementID { owner = r.Owner; domain = r.Domain; break }
    }

    // 2. BFS reverse using GetBacklinks (same pattern as impact.bfsForward)
    visited := map[string]bool{elementID: true}
    queue := []string{elementID}
    var affected []AffectedModule

    for depth := 0; depth < opts.Depth && len(queue) > 0; depth++ {
        var next []string
        for _, elem := range queue {
            backlinks, _ := storage.GetBacklinks(db, specID, elem)  // EXISTING function
            for _, bl := range backlinks {
                sourceID := resolveSourceID(bl)  // follow impact.go pattern
                if visited[sourceID] { continue }
                visited[sourceID] = true
                next = append(next, sourceID)
                // Map sourceID to module/domain via registry
            }
        }
        queue = next
    }

    // 3. Group by domain, filter to module-level, build result
    // Filter: only include invariant/adr/section ref types (skip glossary)
}
```

