## Algorithm

```go
func Analyze(db *sql.DB, specID int64, opts Options) (*CoverageResult, error) {
    invs, _ := storage.ListInvariants(db, specID)
    registry, _ := storage.GetInvariantRegistryEntries(db, specID)  // EXISTING

    result := &CoverageResult{
        Invariants: make(map[string]InvariantCoverage),
        Modules:    make(map[string]ModuleCoverage),
        Domains:    make(map[string]DomainCoverage),
    }

    for _, inv := range invs {
        fields := exemplar.ExtractInvariantFields(inv)
        components := exemplar.ComponentsForType("invariant")
        ic := InvariantCoverage{Title: inv.Title, Components: make(map[string]ComponentStatus)}
        present := 0
        for _, comp := range components {
            score := exemplar.WeakScore(fields[comp], comp, "invariant")
            ic.Components[comp] = ComponentStatus{Present: score > 0, Score: score}
            if score > 0 { present++ }
            if score == 0 || score < 0.5 {
                result.Gaps = append(result.Gaps, inv.InvariantID+":"+comp)
            }
        }
        ic.Completeness = float64(present) / float64(len(components))
        result.Invariants[inv.InvariantID] = ic
    }

